package com.nattechnologies.trastcms.plugins.crm;
import org.springframework.data.domain.*; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import java.util.Optional;
public interface CrmContactRepository extends JpaRepository<CrmContact,String> { Optional<CrmContact> findByEmailIgnoreCase(String email); @Query("select c from CrmContact c where (:status is null or c.status=:status) and (:q='' or lower(concat(c.firstName,' ',coalesce(c.lastName,''))) like lower(concat('%',:q,'%')) or lower(coalesce(c.email,'')) like lower(concat('%',:q,'%')) or lower(coalesce(c.phone,'')) like lower(concat('%',:q,'%'))) order by c.updatedAt desc") Page<CrmContact> search(@Param("q") String q,@Param("status") CrmContactStatus status,Pageable pageable); }
